const BOARD_3D_INSTANCE* ASSEMBLY_3D_MANAGER::FindInstanceForItem( const BOARD_ITEM* aItem ) const
{
    if( !aItem )
        return nullptr;

    const BOARD* itemBoard = aItem->GetBoard();

    if( !itemBoard )
        return nullptr;

    for( const auto& inst : m_boardInstances )
    {
        if( inst.board.get() == itemBoard )
            return &inst;
    }

    return nullptr;
}


