6179	        std::vector<ASSEMBLY_3D_MANAGER::RAYTRACE_INSTANCE>& aOut ) const
6180	{
6181	    aOut.clear();
6182	
6183	    if( m_boardInstances.empty() || m_instanceAdapters.size() != m_boardInstances.size() )
6184	        return;
6185	
6186	    // Mirror the OpenGL composite's centerShared offset so the raytraced
6187	    // scene is co-located with how RedrawAll positions the OpenGL
6188	    // composite (keeps the camera framing identical between engines).
6189	    SFVEC3F bboxMinMm, bboxMaxMm;
6190	    const_cast<ASSEMBLY_3D_MANAGER*>( this )->GetAssemblyBoundingBox(
6191	            bboxMinMm, bboxMaxMm );
6192	    const SFVEC3F centerMm = ( bboxMinMm + bboxMaxMm ) * 0.5f;
6193	    const float   sharedF  = static_cast<float>( m_sharedBiuTo3Dunits );
6194	    const float   biuPerMm = 1.0e6f;
6195	    const glm::vec3 centerShared(  centerMm.x * biuPerMm * sharedF,
6196	                                  -centerMm.y * biuPerMm * sharedF,
6197	                                   centerMm.z * biuPerMm * sharedF );
6198	
6199	    aOut.reserve( m_boardInstances.size() );
6200	
6201	    for( size_t i = 0; i < m_boardInstances.size(); i++ )
6202	    {
6203	        const BOARD_3D_INSTANCE& inst = m_boardInstances[i];
6204	
6205	        if( !inst.visible || !inst.board || !m_instanceAdapters[i] )
6206	            continue;
6207	
6208	        BOARD_ADAPTER* adapter = m_instanceAdapters[i].get();
6209	
6210	        // Match the OpenGL pose math in RedrawAll exactly. Each per-
6211	        // instance adapter has its own biuTo3Dunits; the wrapper's
6212	        // pose carries the shared/local scale ratio so the raytracer's
6213	        // INSTANCE_OBJECT_3D maps the inner per-board scene into the
6214	        // shared assembly frame.
6215	        const double localFactor = adapter->BiuTo3dUnits();
6216	        const double scaleFactor = ( localFactor != 0.0 )
6217	                                       ? m_sharedBiuTo3Dunits / localFactor
6218	                                       : 1.0;
6219	
6220	        const glm::vec3 instShared(  inst.position.x * biuPerMm * sharedF,
6221	                                    -inst.position.y * biuPerMm * sharedF,
6222	                                     inst.position.z * biuPerMm * sharedF );
6223	
6224	        const SFVEC3F   localCenter = adapter->GetBoardCenter();
6225	        const glm::vec3 localCenterShared(
6226	                localCenter.x * static_cast<float>( scaleFactor ),
6227	                localCenter.y * static_cast<float>( scaleFactor ),
6228	                localCenter.z * static_cast<float>( scaleFactor ) );
6229	
6230	        glm::mat4 pose( 1.0f );
6231	        pose = glm::translate( pose, instShared - centerShared );
6232	        pose = glm::translate( pose, localCenterShared );
6233	        pose = glm::rotate( pose, glm::radians( inst.rotation.z ),
