{
    int index = aEvent.GetInt();
    if( index < 0 || index >= static_cast<int>( m_boardUuids.size() ) || !m_manager )
        return;

    bool visible = m_boardListBox->IsChecked( index );
    m_manager->SetBoardVisible( m_boardUuids[index], visible );

    autoRunCollisionCheck();
    refresh3DView();
}

