1247	wxImage EDA_3D_VIEWER_FRAME::captureRaytracingScreenshot( BOARD_ADAPTER& aAdapter, TRACK_BALL& aCamera, const wxSize& aSize )
1248	{
1249	    BOARD_ADAPTER tempadapter;
1250	    tempadapter.SetBoard( GetBoard() );
1251	    tempadapter.m_Cfg = aAdapter.m_Cfg;
1252	    tempadapter.InitSettings( nullptr, nullptr );
1253	    tempadapter.Set3dCacheManager( aAdapter.Get3dCacheManager() );
1254	
1255	    RENDER_3D_RAYTRACE_RAM raytrace( tempadapter, aCamera );
1256	    raytrace.SetCurWindowSize( aSize );
1257	
1258	    // Multi-board (MBS) export: stage the assembly's per-instance
1259	    // descriptor list onto the temporary raytracer the same way the
1260	    // live canvas does. Reload picks it up on the first Redraw and
1261	    // dispatches to ReloadMultiInstance, building one merged scene
1262	    // (per-instance BVH + INSTANCE_OBJECT_3D wrappers) instead of
1263	    // rendering only the active sub-board's BOARD via tempadapter.
1264	    if( IsAssemblyMode() && m_assemblyManager )
1265	    {
1266	        std::vector<ASSEMBLY_3D_MANAGER::RAYTRACE_INSTANCE> raw;
1267	        m_assemblyManager->BuildRaytraceInstances( raw );
1268	
1269	        std::vector<RENDER_3D_RAYTRACE_BASE::INSTANCE_DESC> insts;
1270	        insts.reserve( raw.size() );
1271	
1272	        for( auto& r : raw )
1273	        {
1274	            RENDER_3D_RAYTRACE_BASE::INSTANCE_DESC d;
1275	            d.adapter = r.adapter;
1276	            d.pose    = r.pose;
1277	            insts.push_back( d );
1278	        }
1279	
1280	        raytrace.SetPendingInstances( std::move( insts ) );
1281	        raytrace.ReloadRequest();
1282	    }
1283	
1284	    while( raytrace.Redraw( false, nullptr, nullptr ) );
1285	
1286	    uint8_t* rgbaBuffer = raytrace.GetBuffer();
1287	    wxSize   realSize   = raytrace.GetRealBufferSize();
1288	
1289	    if( !rgbaBuffer )
1290	        return wxImage();
1291	
1292	    return convertRGBAToImage( rgbaBuffer, realSize );
1293	}
