1296	wxImage EDA_3D_VIEWER_FRAME::convertRGBAToImage( uint8_t* aRGBABuffer, const wxSize& aRealSize )
1297	{
1298	    const unsigned int wxh = aRealSize.x * aRealSize.y;
1299	
1300	    unsigned char* rgbBuffer   = (unsigned char*) malloc( wxh * 3 );
1301	    unsigned char* alphaBuffer = (unsigned char*) malloc( wxh );
1302	
1303	    unsigned char* rgbaPtr  = aRGBABuffer;
1304	    unsigned char* rgbPtr   = rgbBuffer;
1305	    unsigned char* alphaPtr = alphaBuffer;
1306	
1307	    for( int y = 0; y < aRealSize.y; y++ )
1308	    {
1309	        for( int x = 0; x < aRealSize.x; x++ )
1310	        {
1311	            rgbPtr[0]   = rgbaPtr[0];
1312	            rgbPtr[1]   = rgbaPtr[1];
1313	            rgbPtr[2]   = rgbaPtr[2];
1314	            alphaPtr[0] = rgbaPtr[3];
1315	
1316	            rgbaPtr  += 4;
1317	            rgbPtr   += 3;
1318	            alphaPtr += 1;
1319	        }
1320	    }
1321	
1322	    wxImage screenshotImage;
1323	    screenshotImage.Create( aRealSize );
1324	    screenshotImage.SetData( rgbBuffer );
1325	    screenshotImage.SetAlpha( alphaBuffer );
1326	    return screenshotImage.Mirror( false );
1327	}
