        const bool inAssembly      = m_assemblyManager != nullptr;
        const bool engineIsOpenGL  = ( m_boardAdapter.m_Cfg->m_Render.engine
                                        == RENDER_ENGINE::OPENGL );
        const bool assemblyComposite   = inAssembly && engineIsOpenGL;
        const bool assemblyRaytraced   = inAssembly && !engineIsOpenGL;

        bool reloadRaytracingForCalculations = false;

        // In MBS mode the main m_3d_render_opengl is never Redraw'd —
        // per-instance renderers paint instead — so its
        // m_reloadRequested flag stays true forever. Triggering the
        // raytracer reload off that flag would rebuild the whole BVH
        // every frame (single-board topology, against the wrong
        // adapter), which crushes mouse/drag responsiveness. The
        // per-instance descriptor staging below is signature-gated
        // and drives the raytracer's reload lifecycle correctly for
        // MBS, so we skip this single-board calculation reload here.
        if( !inAssembly && engineIsOpenGL
                && m_3d_render_opengl->IsReloadRequestPending() )
        {
            reloadRaytracingForCalculations = true;
        }

        // Stage multi-instance descriptors on the raytracer whenever
        // MBS is active, regardless of which engine is rendering.
        // OpenGL-composite mode never uses the raytracer to draw,
        // but it still calls m_3d_render_raytracing->Reload() below
        // (reloadRaytracingForCalculations) so IntersectBoardItem
        // can pick across all sub-boards. Without staging, that
        // pick BVH only covers the active sub-board's geometry —
        // clicks on other boards return null.
        if( inAssembly && m_3d_render_raytracing )
        {
            // Build the per-instance descriptor list using the same
            // pose composition the OpenGL path uses (BOARD_3D_INSTANCE
            // pose feeds straight into the renderer's assembly pose).
            std::vector<ASSEMBLY_3D_MANAGER::RAYTRACE_INSTANCE> raw;
            m_assemblyManager->BuildRaytraceInstances( raw );

            // Compute a signature over the descriptor list. Adapter
            // pointer + 16 pose floats per instance reduced to a
            // 64-bit FNV-style mix. Stable enough that identical
            // poses → identical signature, any change → different
            // signature. Avoids the "trace restarts every frame"
            // bug where calling ReloadRequest each Redraw kept the
            // raytracer stuck at its first preview pass and the
            // multi-stage progressive trace never finished.
            uint64_t sig = 0xcbf29ce484222325ULL;
            auto mix = [&]( uint64_t aChunk )
            {
                sig ^= aChunk;
                sig *= 0x100000001b3ULL;
            };

            for( const auto& r : raw )
            {
                mix( reinterpret_cast<uintptr_t>( r.adapter ) );

                const float* p = &r.pose[0][0];

                for( int idx = 0; idx < 16; idx++ )
