void EDA_3D_CANVAS::releaseOpenGL()
{
    if( m_glRC )
    {
        GL_CONTEXT_MANAGER* gl_mgr = Pgm().GetGLContextManager();

        // PGM_BASE::Destroy() (called from PGM_KICAD::OnPgmExit) tears down
        // the GL context manager BEFORE wxApp::CleanUp runs DeleteAllTLWs to
        // destroy the frames. M4 peer-window MBSCH frames host an
        // EDA_3D_VIEWER_FRAME as a child, so when the MBSCH dtor cascades
        // through wxFrame::DestroyChildren we end up here with gl_mgr null
        // and crash inside LockCtx. Skip the GL teardown — the OS reclaims
        // the entire process within milliseconds, including any leftover GL
        // contexts.
        if( !gl_mgr )
        {
            m_3d_render_raytracing = nullptr;
            m_3d_render_opengl = nullptr;
            m_3d_render = nullptr;
            m_glRC = nullptr;
            return;
        }

        gl_mgr->LockCtx( m_glRC, this );

        // Tear down the assembly manager's per-instance renderers
        // while the context is current. Otherwise their destructors
        // (glDeleteTextures + freeAllLists) run against whatever
        // context happens to be current globally — corrupting OTHER
        // OpenGL windows (GAL editors, MBS canvas). See M6.C teardown
        // note in ASSEMBLY_3D_MANAGER::ReleaseOpenGL.
        if( m_assemblyManager )
            m_assemblyManager->ReleaseOpenGL();

        delete m_3d_render_raytracing;
        m_3d_render_raytracing = nullptr;

        delete m_3d_render_opengl;
        m_3d_render_opengl = nullptr;

        // This is just a copy of a pointer, can safely be set to NULL.
        m_3d_render = nullptr;

        gl_mgr->UnlockCtx( m_glRC );
        gl_mgr->DestroyCtx( m_glRC );
        m_glRC = nullptr;
    }
}


void EDA_3D_CANVAS::OnCloseWindow( wxCloseEvent& event )
{
    releaseOpenGL();

    event.Skip();
}


