404	void RENDER_3D_RAYTRACE_BASE::Reload( REPORTER* aStatusReporter, REPORTER* aWarningReporter,
405	                                 bool aOnlyLoadCopperAndShapes )
406	{
407	    // Top-level dispatch: if the canvas published a multi-instance list
408	    // via SetPendingInstances (the MBS multi-board path), every Reload
409	    // rebuilds the same N-board scene against that list. The list is
410	    // read but not consumed, so any reload trigger (engine toggle,
411	    // duplicate NewDisplay, layer change, etc.) keeps the multi-instance
412	    // build intact. Pre-MOON-1406 we moved this list out on first use,
413	    // which let later Reloads fall through to the single-board path —
414	    // surfacing as "only one board visible" after a panel commit.
415	    if( !m_currentInstances.empty() && !m_overrideContainer )
416	    {
417	        ReloadMultiInstance( m_currentInstances, aStatusReporter, aWarningReporter );
418	        return;
