                                      REPORTER* aWarningReporter )
{
    bool requestAnother = false;
    bool firstPass      = true;

    // MOON-1406 diagnostic: log RedrawAll entry state at most ~once/sec
    // so we can see whether the OpenGL composite path is being reached
    // at all when the symptom fires, and whether per-instance vectors
    // are populated.
    static int64_t  s_lastLogMs    = 0;
    const int64_t   nowMs          = GetRunningMicroSecs() / 1000;
    size_t          renderableCount = 0;
    for( size_t i = 0; i < m_boardInstances.size(); i++ )
    {
        const BOARD_3D_INSTANCE& inst = m_boardInstances[i];
        if( inst.visible && inst.board && i < m_instanceRenderers.size()
            && m_instanceRenderers[i] )
        {
            renderableCount++;
        }
    }

    if( nowMs - s_lastLogMs > 500 )
