{
    wxLogMessage( wxT( "[POS-DIAG] onPositionChanged ENTER selIdx=%d mgr=%p" ),
                  m_selectedBoardIndex, static_cast<void*>( m_manager ) );

    if( m_selectedBoardIndex == wxNOT_FOUND || !m_manager )
